--
-- Table structure for table `daily_stock_counts`
--

DROP TABLE IF EXISTS `daily_stock_counts`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `daily_stock_counts` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `daily_reconciliation_id` int(11) NOT NULL,
  `product_id` int(11) NOT NULL,
  `opening_qty` int(11) DEFAULT 0,
  `added_qty` int(11) DEFAULT 0,
  `lost_damaged_qty` int(11) DEFAULT 0,
  `discounted_qty` int(11) DEFAULT 0,
  `closing_qty` int(11) DEFAULT 0,
  `calculated_sold_qty` int(11) DEFAULT 0,
  `expected_revenue` decimal(10,2) DEFAULT 0.00,
  `created_by` int(11) DEFAULT NULL,
  `created_at` datetime DEFAULT current_timestamp(),
  `updated_by` int(11) DEFAULT NULL,
  `updated_at` datetime DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  PRIMARY KEY (`id`),
  KEY `daily_reconciliation_id` (`daily_reconciliation_id`),
  KEY `product_id` (`product_id`),
  CONSTRAINT `daily_stock_counts_ibfk_1` FOREIGN KEY (`daily_reconciliation_id`) REFERENCES `daily_reconciliations` (`id`) ON DELETE CASCADE,
  CONSTRAINT `daily_stock_counts_ibfk_2` FOREIGN KEY (`product_id`) REFERENCES `products` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=737 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

