CREATE TABLE `yencha_ingredients` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `name` varchar(255) NOT NULL,
  `unit` varchar(50) NOT NULL COMMENT 'หน่วยบรรจุที่ใช้ตัดสต็อก เช่น ถุง, ขวด, กล่อง',
  `stock_qty` decimal(10,2) DEFAULT 0.00 COMMENT 'จำนวนหน่วยบรรจุคงเหลือปัจจุบัน',
  `min_qty` decimal(10,2) DEFAULT 2.00 COMMENT 'จุดแจ้งเตือนเมื่อเหลือน้อย',
  `quantity_per_unit` decimal(10,2) DEFAULT 1.00 COMMENT 'ปริมาณเนื้อในต่อ 1 หน่วยบรรจุ (เช่น 500)',
  `purchase_price` decimal(10,2) DEFAULT 0.00 COMMENT 'ราคาล่าสุดในหน้าวัตถุดิบ',
  `base_unit_name` varchar(50) DEFAULT 'กรัม' COMMENT 'ชื่อหน่วยย่อย (เช่น กรัม, มล.)',
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `updated_at` timestamp NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `is_active` tinyint(1) DEFAULT 1,
  PRIMARY KEY (`id`),
  UNIQUE KEY `name` (`name`)
) ENGINE=InnoDB AUTO_INCREMENT=54 DEFAULT CHARSET=utf8mb4;
