  `id` int(11) NOT NULL AUTO_INCREMENT,
  `ingredient_id` int(11) NOT NULL,
  `type` enum('in','out') NOT NULL COMMENT 'in = รับเข้า, out = เบิกออก',
  `qty` decimal(10,2) NOT NULL,
