  `old_qty` decimal(10,2) NOT NULL COMMENT 'สต็อกก่อนเปลี่ยน',
  `new_qty` decimal(10,2) NOT NULL COMMENT 'สต็อกหลังเปลี่ยน',
  `user_id` int(11) NOT NULL,
  `note` varchar(255) DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT current_timestamp(),
  `status` enum('active','canceled') DEFAULT 'active' COMMENT 'ยกเลิก หรือใช้งานรายการนี้',
  PRIMARY KEY (`id`),
  KEY `ingredient_id` (`ingredient_id`),
  CONSTRAINT `yencha_stock_log_ibfk_1` FOREIGN KEY (`ingredient_id`) REFERENCES `yencha_ingredients` (`id`)
) ENGINE=InnoDB AUTO_INCREMENT=423 DEFAULT CHARSET=utf8mb4;
